import{_ as r,C as t,o as d,c as o,a1 as s,E as l,j as e,a as i}from"./chunks/framework.Clqesclh.js";const p="/images/nanjing/nanjing0.png",P=JSON.parse('{"title":"南京四日游","description":"","frontmatter":{"title":"南京四日游","date":"2023-11-16T02:01:23.000Z","recommend":false},"headers":[],"relativePath":"posts/nanjing.md","filePath":"posts/nanjing.md"}'),m={name:"posts/nanjing.md"};function u(y,a,h,g,b,f){const n=t("ImageGallery");return d(),o("div",null,[a[0]||(a[0]=s("",12)),l(n,{dir:"/images/nanjing/day1/"}),a[1]||(a[1]=e("h2",{id:"day2-钟山风景区-明孝陵、美龄宫、中山陵、音乐台-侵华日军南京大屠杀遇难同胞纪念馆",tabindex:"-1"},[i("Day2 钟山风景区（明孝陵、美龄宫、中山陵、音乐台）- 侵华日军南京大屠杀遇难同胞纪念馆 "),e("a",{class:"header-anchor",href:"#day2-钟山风景区-明孝陵、美龄宫、中山陵、音乐台-侵华日军南京大屠杀遇难同胞纪念馆","aria-label":'Permalink to "Day2 钟山风景区（明孝陵、美龄宫、中山陵、音乐台）- 侵华日军南京大屠杀遇难同胞纪念馆"'},"​")],-1)),a[2]||(a[2]=e("p",null,"钟山风景区离市中心很近，明孝陵、美龄宫、中山陵、音乐台都在景区范围内，去之前可以在网上购买优惠套票，凭身份证可连续两天进入景区，中山陵不包含在套票内，需要提前单独预约，景区推荐游览路线是明孝陵、美龄宫、中山陵、音乐台。",-1)),a[3]||(a[3]=e("p",null,"我们乘坐地铁2号线到苜蓿园站1号口出来后找到陵园路，也就是大家所说的梧桐大道，这条路是当年为中山陵修的，梧桐也是那个时候栽的，我们边走边捡地上的梧桐叶，为期三天的拔根儿比赛就从今天开始，首战以失败告终，拔了几次，居然一次没赢...沿陵园路走一会就到了明孝陵5号口，明孝陵是明太祖朱元璋与大脚马皇后的合葬墓，进入景区走几十米来到石象路，它是明孝陵神道的第一段，路两侧有石兽六种共十二对，依次是狮子、獬豸、骆驼、大象、麒麟、马，每种四只，一对卧着一对站着，它们都是公的，据说是以阳守阴的意思，神道的第二段叫翁仲路，路两边有四对文臣武将，从胡须上能看出他们年龄不同，意味着大明王朝后继有人，穿过神道没多远就到了陵宫，参观后沿原路返回从5号口出来后没多远就是美龄宫，据说当年宋美龄很喜欢这个地方，然后蒋介石就花公款在这里建了别墅，他们在这里居住、办公、会客，从美龄宫出来后再走几分钟就到了中山陵，墓道两边种满了雪松，音乐台在中山陵广场边上，是后来修建的，用来纪念孙中山先生时做音乐表演和集会演讲，这里有很多鸽子，还可以在附近买些吃的进行投喂，穿过音乐台我们乘十元一人的两轮电动车离开钟山风景区到达附近的地铁站，师傅说再坐两人都没问题...",-1)),a[4]||(a[4]=e("p",null,"乘地铁2号线在云锦路站2号口出来，路边就是侵华日军南京大屠杀遇难同胞纪念馆，这是一处以史料文物、建筑、雕塑、影视等综合形式，全面展示“南京大屠杀”惨案的专史陈列馆，展出的史料包括当年日军屠杀现场照片、幸存者名册及证词、大屠杀时日军使用的军用品、犯下罪行的日军官兵日记及供词等，门票需要提前免费预约，每天早上7点在官方公众号上放一周后的票，进入纪念馆安检后可以自愿扫码捐钱，然后领取一朵白菊花，我们把它放在了张纯如的雕塑前，参观完纪念馆后，晚上来到老门东吃晚饭，还买了一瓶酒。",-1)),l(n,{dir:"/images/nanjing/day2/"}),a[5]||(a[5]=e("h2",{id:"day3-牛首山-—-颐和路-—-德基广场",tabindex:"-1"},[i("Day3 牛首山 — 颐和路 — 德基广场 "),e("a",{class:"header-anchor",href:"#day3-牛首山-—-颐和路-—-德基广场","aria-label":'Permalink to "Day3 牛首山 — 颐和路 — 德基广场"'},"​")],-1)),a[6]||(a[6]=e("p",null,"中午去李记清真馆吃锅贴，点完单后才知道门口的长队是凭小票领锅贴的，队伍边上居然还有黄牛，排了大概40分钟，好在味道不错，没有失望，吃完饭便打车去牛首山，牛首山景区很大，这次来主要是想看下佛顶宫，景区离市区较远，地铁不能直达，参观完富丽堂皇的佛顶宫后便离开了，我们坐地铁来到颐和路附近，这里有很多民国政府要员的宅第公馆，即使下着雨路边也经常能看到拍照的人，后来在一个貌似环岛的地方找到了先锋书店，在这里买了好看的冰箱贴，离开书店沿颐和路走到江苏省人民政府门口后打车去德基广场，商场很大吃饭地方不多，生意最好的南京大排档 19:00 多时就已经不放号了，去别家拿号等了一个小时才吃上，在楼下买水也等了一个半小时，这里排号也有黄牛...德基广场里价值上百万、上千万的厕所，我们只去了五百万那个，没有想象的豪华。",-1)),l(n,{dir:"/images/nanjing/day3/"}),a[7]||(a[7]=e("h2",{id:"day4-古鸡鸣寺-总统府-返程",tabindex:"-1"},[i("Day4 古鸡鸣寺 - 总统府 - 返程 "),e("a",{class:"header-anchor",href:"#day4-古鸡鸣寺-总统府-返程","aria-label":'Permalink to "Day4 古鸡鸣寺 - 总统府 - 返程"'},"​")],-1)),a[8]||(a[8]=e("p",null,"古鸡鸣寺始建于西晋，是南京最古老、香火最旺的佛寺之一，地铁3号线可直达，来这里不用提前买票，在寺门口花十元购买“香花券”便可以进入了，进到寺内先找厕所拉屎，然后逛到最高处，免费领香供奉后便离开了，总共用时大概一小时，出来后便骑车来到不远的总统府，这里曾是国民政府中央所在地，也见证了太平天国与两江总督衙门的兴衰，大致参观后便回酒店拿上行礼，打车去高铁站准备回家。",-1)),l(n,{dir:"/images/nanjing/day4/"}),a[9]||(a[9]=e("h2",{id:"最后附上景点地铁路线图",tabindex:"-1"},[i("最后附上景点地铁路线图 "),e("a",{class:"header-anchor",href:"#最后附上景点地铁路线图","aria-label":'Permalink to "最后附上景点地铁路线图"'},"​")],-1)),a[10]||(a[10]=e("p",null,[e("img",{src:p,alt:"景点地铁路线图",title:"景点地铁路线图"})],-1))])}const k=r(m,[["render",u]]);export{P as __pageData,k as default};
